      { name: "Youssef En-Nesyri", nameArabic: "يوسف النصيري", position: "ST", stats: "2 Goals (Historic Header)", image: "https://upload.wikimedia.org/wikipedia/commons/thumb/2/26/Ennesyri.jpg/500px-Ennesyri.jpg", description: "Youssef En-Nesyri is a phenomenal aerial threat and a deeply hardworking striker who leads the line with endless tenacity. He wrote his name into footballing immortality when his iconic, towering 2.78-meter header against Portugal sent Morocco into the 2022 World Cup semi-finals, becoming the first African nation ever to reach that stage.", number: 19, grid: { x: 50, y: 15 } },
      { name: "Sofiane Boufal", nameArabic: "سفيان بوفال", position: "LW", stats: "Dribbling Wizard", image: "https://upload.wikimedia.org/wikipedia/commons/thumb/f/f9/Southampton_FC_versus_Sevilla_%2836346327746%29.jpg/500px-Southampton_FC_versus_Sevilla_%2836346327746%29.jpg", description: "A mercurial talent and absolute joy to watch, Sofiane Boufal brings street-football flair, devastating dribbling, and unpredictability to the Moroccan attack. His ability to humiliate defenders in 1-on-1 situations and his emotional celebrations with his mother at the 2022 World Cup made him a beloved fan-favorite worldwide.", number: 17, grid: { x: 20, y: 25 } }
